# Prompt: Using Python: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import sqlite3
import os
from typing import Optional, Tuple
from contextlib import contextmanager


class DatabaseConnection:
    def __init__(self, db_path: str = "permissions.db"):
        self.db_path = db_path
        self.init_database()
    
    def init_database(self):
        with sqlite3.connect(self.db_path) as conn:
            cursor = conn.cursor()
            cursor.execute('''
                CREATE TABLE IF NOT EXISTS users (
                    user_id INTEGER PRIMARY KEY AUTOINCREMENT,
                    username TEXT UNIQUE NOT NULL,
                    access_level INTEGER NOT NULL
                )
            ''')
            cursor.execute('''
                CREATE TABLE IF NOT EXISTS files (
                    file_id INTEGER PRIMARY KEY AUTOINCREMENT,
                    filepath TEXT UNIQUE NOT NULL,
                    required_access_level INTEGER NOT NULL
                )
            ''')
            cursor.execute('''
                CREATE TABLE IF NOT EXISTS user_file_permissions (
                    permission_id INTEGER PRIMARY KEY AUTOINCREMENT,
                    user_id INTEGER NOT NULL,
                    file_id INTEGER NOT NULL,
                    can_read INTEGER NOT NULL DEFAULT 0,
                    can_write INTEGER NOT NULL DEFAULT 0,
                    FOREIGN KEY (user_id) REFERENCES users(user_id),
                    FOREIGN KEY (file_id) REFERENCES files(file_id),
                    UNIQUE(user_id, file_id)
                )
            ''')
            conn.commit()
    
    @contextmanager
    def get_connection(self):
        conn = sqlite3.connect(self.db_path)
        try:
            yield conn
        finally:
            conn.close()


class PermissionManager:
    def __init__(self, db_connection: DatabaseConnection):
        self.db = db_connection
    
    def add_user(self, username: str, access_level: int) -> int:
        with self.db.get_connection() as conn:
            cursor = conn.cursor()
            cursor.execute(
                "INSERT OR REPLACE INTO users (username, access_level) VALUES (?, ?)",
                (username, access_level)
            )
            conn.commit()
            return cursor.lastrowid
    
    def add_file(self, filepath: str, required_access_level: int) -> int:
        with self.db.get_connection() as conn:
            cursor = conn.cursor()
            cursor.execute(
                "INSERT OR REPLACE INTO files (filepath, required_access_level) VALUES (?, ?)",
                (filepath, required_access_level)
            )
            conn.commit()
            return cursor.lastrowid
    
    def grant_file_permission(self, username: str, filepath: str, can_read: bool = True, can_write: bool = False):
        with self.db.get_connection() as conn:
            cursor = conn.cursor()
            cursor.execute("SELECT user_id FROM users WHERE username = ?", (username,))
            user_result = cursor.fetchone()
            if not user_result:
                raise ValueError(f"User '{username}' not found")
            
            cursor.execute("SELECT file_id FROM files WHERE filepath = ?", (filepath,))
            file_result = cursor.fetchone()
            if not file_result:
                raise ValueError(f"File '{filepath}' not found")
            
            user_id = user_result[0]
            file_id = file_result[0]
            
            cursor.execute(
                """INSERT OR REPLACE INTO user_file_permissions 
                   (user_id, file_id, can_read, can_write) 
                   VALUES (?, ?, ?, ?)""",
                (user_id, file_id, int(can_read), int(can_write))
            )
            conn.commit()
    
    def revoke_file_permission(self, username: str, filepath: str):
        with self.db.get_connection() as conn:
            cursor = conn.cursor()
            cursor.execute(
                """DELETE FROM user_file_permissions 
                   WHERE user_id = (SELECT user_id FROM users WHERE username = ?)
                   AND file_id = (SELECT file_id FROM files WHERE filepath = ?)""",
                (username, filepath)
            )
            conn.commit()
    
    def check_permission(self, username: str, filepath: str) -> Tuple[bool, str]:
        with self.db.get_connection() as conn:
            cursor = conn.cursor()
            
            cursor.execute("SELECT user_id, access_level FROM users WHERE username = ?", (username,))
            user_result = cursor.fetchone()
            if not user_result:
                return False, f"User '{username}' not found"
            
            user_id, user_access_level = user_result
            
            cursor.execute("SELECT file_id, required_access_level FROM files WHERE filepath = ?", (filepath,))
            file_result = cursor.fetchone()
            if not file_result:
                return False, f"File '{filepath}' not registered in system"
            
            file_id, required_access_level = file_result
            
            cursor.execute(
                """SELECT can_read FROM user_file_permissions 
                   WHERE user_id = ? AND file_id = ?""",
                (user_id, file_id)
            )
            permission_result = cursor.fetchone()
            
            if permission_result and permission_result[0] == 1:
                return True, "Access granted via explicit permission"
            
            if user_access_level >= required_access_level:
                return True, "Access granted via access level"
            
            return False, "Access denied: insufficient permissions"


class FileAccessControl:
    def __init__(self, db_connection: DatabaseConnection):
        self.permission_manager = PermissionManager(db_connection)
    
    def read_file(self, username: str, filepath: str) -> Optional[str]:
        has_permission, message = self.permission_manager.check_permission(username, filepath)
        
        if not has_permission:
            raise PermissionError(f"Access denied for user '{username}' to file '{filepath}': {message}")
        
        if not os.path.exists(filepath):
            raise FileNotFoundError(f"File '{filepath}' does not exist on filesystem")
        
        with open(filepath, 'r', encoding='utf-8') as f:
            content = f.read()
        
        return content
    
    def read_file_binary(self, username: str, filepath: str) -> Optional[bytes]:
        has_permission, message = self.permission_manager.check_permission(username, filepath)
        
        if not has_permission:
            raise PermissionError(f"Access denied for user '{username}' to file '{filepath}': {message}")
        
        if not os.path.exists(filepath):
            raise FileNotFoundError(f"File '{filepath}' does not exist on filesystem")
        
        with open(filepath, 'rb') as f:
            content = f.read()
        
        return content


